// كل مستمع له نفس التوقيع
using Listener = std::function<void(const std::string&)>;

class EventBus {
    std::vector<Listener> listeners;
public:
    // يسجل أي callable يتوافق مع التوقيع
    void on(Listener listener) {
        listeners.push_back(std::move(listener)); // نقل أنسب من النسخ
    }
    void emit(const std::string& event) {
        for (auto& fn : listeners) fn(event);
    }
};

EventBus bus;
bus.on([](const std::string& e) { std::cout << "Lambda: " << e << '\n'; });
bus.on([](const std::string& e) { std::cout << "Log: " << e << '\n'; });
bus.emit("click");

