#include <optional>
#include <string>

std::optional<std::string> find_extension(std::string_view filename) {
    auto pos = filename.rfind('.');
    if (pos == std::string_view::npos) return std::nullopt;
    return std::string(filename.substr(pos + 1));
}

auto ext = find_extension("hero.png");

// has_value() أو operator bool للتحقق
if (ext.has_value()) {
    std::cout << *ext; // * يُرجع القيمة (UB إذا كان فارغًا!)
}

// value_or: أرجع القيمة أو بديلًا — الأكثر استخدامًا
