// تحويل نص إلى عدد بأمان — لا استثناءات
std::optional<int> safe_stoi(std::string_view sv) {
    int value;
    auto [ptr, ec] = std::from_chars(sv.data(), sv.data() + sv.size(), value);
    if (ec != std::errc{}) return std::nullopt;
    return value;
}

