template<typename Alloc>
void allocate_and_construct(Alloc& alloc, int count) {
    using Traits = std::allocator_traits<Alloc>;
    using T = typename Traits::value_type;

    T* ptr = Traits::allocate(alloc, count);
    for (int i = 0; i < count; ++i) {
        Traits::construct(alloc, ptr + i, T{});
    }
    std::cout << count << " objects constructed\n";
    for (int i = 0; i < count; ++i) {
        Traits::destroy(alloc, ptr + i);
    }
    Traits::deallocate(alloc, ptr, count);
}

